function _jsMatmulRelu(x, W, b) {
  const out = new Array(b.length).fill(0);
  for (let j = 0; j < b.length; j++) {
    let s = b[j];
    for (let i = 0; i < x.length; i++) s += x[i] * W[i][j];
    out[j] = s > 0 ? s : 0;
  }
  return out;
}

function _jsInfer(features) {
  const { W1, b1, W2, b2, W3, b3 } = _BUNDLED_WEIGHTS;
  const w = W1.length;  // W1 shape is [input_size × hidden_size], so W1.length = input_size = 8
  const x = features.length >= w ? Array.from(features).slice(0, w)
                                  : [...features, ...Array(w - features.length).fill(0)];
  const h1    = _jsMatmulRelu(x, W1, b1);
  const h2    = _jsMatmulRelu(h1, W2, b2);
  let logit = b3[0];
  for (let i = 0; i < h2.length; i++) logit += h2[i] * W3[i][0];
  const pUp = 1 / (1 + Math.exp(-logit));
  return [1 - pUp, pUp];   // [P(down), P(up)] matching skl2onnx "probabilities" layout
}
let _useBundledJs = true;   // flipped to false when ORT loads a retrained model

let _ofiSession     = null;
let _ofiInputWidth  = 12;  // [delta_bid_L1..L5, delta_ask_L1..L5, vpin, spread_norm]

// Probe the model's expected input width by running dummy tensors.
async function _probeWidth(ort, session) {
  for (const w of [13, 12, 11, 8]) {
    try {
      const dummy = new ort.Tensor("float32", new Float32Array(w).fill(0), [1, w]);
      await session.run({ float_input: dummy });
      return w;
    } catch (_) { /* try next */ }
  }
  return 8;
}

async function _loadSession(sourceUrl) {
  const ort = await _ensureOrt();
  const session = await Promise.race([
    ort.InferenceSession.create(sourceUrl, {
      executionProviders:     _execProviders,
      graphOptimizationLevel: "all",
    }),
    new Promise((_, reject) =>
      setTimeout(() => reject(new Error("ONNX session init timed out after 45 s")), 45_000)
    ),
  ]);
  _modelInputWidth = await _probeWidth(ort, session);
  return session;
}

async function _loadOfiSession() {
  try {
    const ort      = await _ensureOrt();
    const ref      = new URL("../models/ofi_model.onnx", import.meta.url);
    const modelUrl = _isNodeRuntime ? ref.pathname : ref.href;
    const session  = await ort.InferenceSession.create(modelUrl, {
      executionProviders:     _execProviders,
      graphOptimizationLevel: "all",
    });
    _ofiInputWidth = await _probeWidth(ort, session);
    _ofiSession    = session;
    console.info("[inference] OFI model loaded — width:", _ofiInputWidth);
  } catch (_) {
    console.info("[inference] OFI model not found — OFI forecasting disabled");
  }
}

async function _load() {
  if (_useBundledJs) {
    // Bundled JS model runs instantly — no ORT-WASM compilation needed.
    // A retrained model delivered via reload_model will flip _useBundledJs off.
    self.postMessage({ type: "inference_ready" });
    console.info("[inference] bundled JS model ready — width:", _BUNDLED_WEIGHTS.W1.length);
    await _loadOfiSession();
    return;
  }
  try {
    const _modelRef = new URL("../models/signal_model.onnx", import.meta.url);
    const modelUrl  = _isNodeRuntime ? _modelRef.pathname : _modelRef.href;
    _session = await _loadSession(modelUrl);
    self.postMessage({ type: "inference_ready" });
    console.info("[inference] model loaded — inputs:", _session.inputNames,
      "outputs:", _session.outputNames, "width:", _modelInputWidth);
  } catch (err) {
    console.error("[inference] load failed:", err);
    self.postMessage({ type: "inference_error", error: err.message });
  }
  await _loadOfiSession();
}

self.onmessage = async (ev) => {
  const msg = ev.data;

  if (msg.type === "init") {
    await _load();
    return;
  }

  if (msg.type === "reload_model") {
    try {
      const ort        = await _ensureOrt();
      const raw        = msg.model_bytes ?? msg.buffer;
      const newSession = await ort.InferenceSession.create(new Uint8Array(raw), {
        executionProviders:     _execProviders,
        graphOptimizationLevel: "all",
      });
      _modelInputWidth = await _probeWidth(ort, newSession);
      _session         = newSession;
      _useBundledJs    = false;   // retrained ORT model takes over from bundled JS
      self.postMessage({ type: "inference_ready", retrained: true });
      console.info("[inference] hot-reloaded retrained model — width:", _modelInputWidth);
    } catch (err) {
      console.error("[inference] hot-reload failed:", err);
      self.postMessage({ type: "inference_error", error: err.message });
    }
    return;
  }

  if (msg.type === "reload_ofi_model") {
    try {
      const ort        = await _ensureOrt();
      const raw        = msg.model_bytes ?? msg.buffer;
      const newSession = await ort.InferenceSession.create(new Uint8Array(raw), {
        executionProviders:     _execProviders,
        graphOptimizationLevel: "all",
      });
      _ofiInputWidth = await _probeWidth(ort, newSession);
      _ofiSession    = newSession;
      console.info("[inference] OFI model hot-reloaded — width:", _ofiInputWidth);
    } catch (err) {
      console.error("[inference] OFI hot-reload failed:", err);
    }
    return;
  }

  if (msg.type === "ofi_infer") {
    if (!_ofiSession) return;
    try {
      const ort = await _ensureOrt();
      const w = _ofiInputWidth;
      const raw = msg.features;
      const vec = raw.length >= w ? raw.slice(0, w) : [...raw, ...Array(w - raw.length).fill(0)];
      const tensor  = new ort.Tensor("float32", Float32Array.from(vec), [1, w]);
      const results = await _ofiSession.run({ float_input: tensor });
      const probs   = results["probabilities"].data;
      const pUp     = probs[1];
      self.postMessage({
        type:       "ofi_result",
        ofi_bias:   +((pUp - 0.5) * 2).toFixed(4),
        confidence: +pUp.toFixed(4),
        timestamp:  Date.now(),
      });
    } catch (err) {
      console.error("[inference] OFI run failed:", err);
    }
    return;
  }

  if (msg.type === "infer") {
    const { features, pattern_id, regime_tag, fee, slippage, jury_id, feature_noise } = msg;

    try {
      // Jury ensemble: apply small Gaussian noise for model uncertainty estimation.
      // Box-Muller transform produces normally distributed noise; tiny scale keeps
      // features semantically valid while introducing enough variance for consensus detection.
      let inFeatures = features;
      if (feature_noise > 0) {
        inFeatures = features.map(f => {
          const u1 = Math.random() || 1e-10;
          const u2 = Math.random();
          const z  = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
          return f + z * feature_noise;
        });
      }

      let pUp;
      if (_useBundledJs) {
        const probs = _jsInfer(inFeatures);
        pUp = probs[1];
      } else {
        if (!_session) return;
        const ort = await _ensureOrt();
        const w = _modelInputWidth;
        const featureVec = inFeatures.length >= w
          ? inFeatures.slice(0, w)
          : [...inFeatures, ...Array(w - inFeatures.length).fill(0)];

        const tensor  = new ort.Tensor("float32", Float32Array.from(featureVec), [1, w]);
        const results = await _session.run({ float_input: tensor });
        const probs   = results["probabilities"].data;
        pUp = probs[1];
      }

      const gross_delta = (pUp - 0.5) * 0.03;
      self.postMessage({
        type:        "inference_result",
        pattern_id,
        regime_tag,
        gross_delta: +gross_delta.toFixed(7),
        p_up:        +pUp.toFixed(4),
        features,    // echo back original (un-noised) features for outcome log
        fee,
        slippage,
        ...(jury_id != null ? { jury_id } : {}),
        timestamp:   Date.now(),
      });
    } catch (err) {
      console.error("[inference] run failed:", err);
    }
  }
};
